SELECT p.*, ste.site_nm AS site_nm, cat.category_nm AS category_nm, prd.prod_nm AS prod_nm FROM pd_category_prod p LEFT JOIN sy_site ste ON ste.site_id = p.site_id LEFT JOIN pd_category cat ON cat.category_id = p.category_id LEFT JOIN pd_prod prd ON prd.prod_id = p.prod_id
ORDER BY p.category_prod_id ASC ORDER BY p.category_prod_id DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

