site_id = #{siteId}, category_id = #{categoryId}, prod_id = #{prodId}, category_prod_type_cd = #{categoryProdTypeCd}, sort_ord = #{sortOrd}, emphasis_cd = #{emphasisCd}, disp_yn = #{dispYn}, disp_start_date = #{dispStartDate}, disp_end_date = #{dispEndDate},
WHERE category_prod_id = #{categoryProdId}
